                                      prepare,
                                      stub_monitor,
                                      std::nullopt,
                                      instance_dir);

    EXPECT_TRUE(QFileInfo::exists(file_name));

    vault.prune_expired_images();

    EXPECT_FALSE(QFileInfo::exists(file_name));
}

