36	const EVP_MD* to_evp_md(mp::ImageVaultUtils::EHashAlgorithm algo)
37	{
38	    using enum mp::ImageVaultUtils::EHashAlgorithm;
39	    switch (algo)
40	    {
41	    case sha256:
42	        return EVP_sha256();
43	    case sha512:
44	        return EVP_sha512();
45	    default:
46	        throw std::runtime_error("Unsupported hash algorithm");
47	    }
48	}
49	
50	} // namespace
51	
52	mp::ImageVaultUtils::ImageVaultUtils(const PrivatePass& pass) noexcept : Singleton{pass}
53	{
54	}
55	
56	std::filesystem::path mp::ImageVaultUtils::copy_to_dir(
57	    const std::filesystem::path& file,
58	    const std::filesystem::path& output_dir) const
59	{
60	    if (file.empty())
61	        return "";
62	
63	    if (!MP_FILEOPS.exists(file))
64	        throw std::runtime_error(fmt::format("File {} not found", file));
65	
66	    auto new_location = output_dir / file.filename();
67	
68	    // Normalize the path to platform's preferred slashes
69	    new_location.make_preferred();
70	
71	    MP_FILEOPS.copy(file, new_location, {});
72	    return new_location;
73	}
74	
75	std::string mp::ImageVaultUtils::compute_hash(std::istream& stream, EHashAlgorithm algo) const
76	{
77	    auto ctx =
78	        std::unique_ptr<EVP_MD_CTX, decltype(&EVP_MD_CTX_free)>(EVP_MD_CTX_new(), EVP_MD_CTX_free);
79	
80	    if (!ctx || EVP_DigestInit_ex(ctx.get(), to_evp_md(algo), nullptr) != 1)
81	        throw std::runtime_error("Failed to initialize hash context");
82	
83	    constexpr std::size_t buf_size = 8192;
84	    char buf[buf_size] = {0};
85	    do
86	    {
87	        stream.read(buf, buf_size);
88	        if (stream.bad())
89	            throw std::runtime_error("Failed to read data from device to hash");
90	        if (auto count = stream.gcount(); count > 0)
91	        {
92	            if (EVP_DigestUpdate(ctx.get(), buf, static_cast<size_t>(count)) != 1)
93	                throw std::runtime_error("Failed to update hash");
94	        }
95	
96	    } while (stream);
97	
98	    unsigned char digest[EVP_MAX_MD_SIZE] = {0};
99	    unsigned int digest_len = 0;
100	    if (EVP_DigestFinal_ex(ctx.get(), digest, &digest_len) != 1)
101	        throw std::runtime_error("Failed to finalize hash");
102	
103	    return fmt::format("{:02x}", fmt::join(digest, digest + digest_len, ""));
104	}
105	
106	std::string mp::ImageVaultUtils::compute_file_hash(const std::filesystem::path& path,
107	                                                   EHashAlgorithm algo) const
108	{
109	    std::fstream file;
110	    MP_FILEOPS.open(file, path, std::ios::in | std::ios::binary);
111	    if (!file)
112	        throw std::runtime_error(fmt::format("Failed to open {}", path));
113	
114	    return compute_hash(file, algo);
115	}
116	
117	void mp::ImageVaultUtils::verify_file_hash(const std::filesystem::path& file,
118	                                           const std::string& hash) const
119	{
120	    const std::string sha512_prefix = "sha512:";
121	    std::string hash_to_check = hash;
122	    EHashAlgorithm algo = EHashAlgorithm::sha256;
123	
124	    if (utils::istarts_with(hash, sha512_prefix))
125	    {
126	        hash_to_check = hash.substr(sha512_prefix.length());
127	        algo = EHashAlgorithm::sha512;
128	    }
129	
130	    const auto file_hash = compute_file_hash(file, algo);
131	
132	    if (!utils::iequals(file_hash, hash_to_check))
133	    {
134	        throw std::runtime_error(fmt::format("Hash of {} does not match (expected {} but got {})",
135	                                             file,
136	                                             hash_to_check,
137	                                             file_hash));
138	    }
139	}
140	
141	std::filesystem::path mp::ImageVaultUtils::extract_file(const std::filesystem::path& file,
142	                                                        const Decoder& decoder,
143	                                                        bool delete_original) const
144	{
145	    const auto new_path = MP_FILEOPS.remove_extension(file);
146	    decoder(file, new_path);
147	
148	    if (delete_original)
149	    {
150	        std::error_code ec{};
151	        MP_FILEOPS.remove(file, ec);
152	    }
153	
154	    return new_path;
155	}
156	
157	mp::ImageVaultUtils::HostMap mp::ImageVaultUtils::configure_image_host_map(
158	    const Hosts& image_hosts) const
159	{
160	    HostMap remote_image_host_map{};
161	    for (const auto& image_host : image_hosts)
162	    {
163	        for (const auto& remote : image_host->supported_remotes())
164	        {
165	            remote_image_host_map[remote] = image_host;
166	        }
167	    }
168	
169	    return remote_image_host_map;
170	}
