                                      default_query,
                                      stub_prepare,
                                      stub_monitor,
                                      std::nullopt,
                                      instance_dir);

    EXPECT_THAT(url_downloader.downloaded_files.size(), Eq(1));
    EXPECT_TRUE(url_downloader.downloaded_urls.contains(host.image.url()));
}

